#ifdef ENABLE_PARSEC_HOOKS
#include <hooks.h>
#endif

using namespace std;

#define MAXNAMESIZE 1024 
#define SEED 1
#define SP 1 
#define ITER 3 
#define PROFILE 
#define CACHE_LINE 512 

typedef struct {
  float weight;
  float *coord;
  long assign;  
  float cost;  
} Point;

typedef struct {
  long num; 
  int dim;  
  Point *p; 
} Points;

static bool *switch_membership; 
static bool* is_center; 
static int* center_table; 
float* block;

static int nproc; 
static int c, d;
static int ompthreads;

#ifdef PROFILE
double time_local_search;
double time_speedy;
double time_select_feasible;
double time_gain;
double time_shuffle;
double time_gain_dist;
double time_gain_init;
#endif 

double gettime() {
  struct timeval t;
  gettimeofday(&t,NULL);
  return (double)t.tv_sec+t.tv_usec*1e-6;
}

int isIdentical(float *i, float *j, int D)
{
  int a = 0;
  int equal = 1;
  while (equal && D > a) {
    if (j[a] != i[a]) equal = 0;
    else a++;
  }
  if (equal) return 1;
  else return 0;
}

static int compute_0(const void *i, const void *j)
{
  float a, b;
  a = *(float *)(i);
  b = *(float *)(j);
  if (a > b) return (1);
  if (b > a) return (-1);
  return(0);
}

void shuffle(Points *points)
{
#ifdef PROFILE
  double t1 = gettime();
#endif
  long i, j;
  Point temp;
  for (i=0;i<points->num-1;i++) {
    j=(lrand48()%(points->num - i)) + i;
    temp = points->p[i];
    points->p[i] = points->p[j];
    points->p[j] = temp;
  }
#ifdef PROFILE
  double t2 = gettime();
  time_shuffle += t2-t1;
#endif
}

void intshuffle(int *intarray, int length)
{
#ifdef PROFILE
  double t1 = gettime();
#endif
  long i, j;
  int temp;
  for (i=0;length > i;i++) {
    j=(lrand48()%(length - i))+i;
    temp = intarray[i];
    intarray[i]=intarray[j];
    intarray[j]=temp;
  }
#ifdef PROFILE
  double t2 = gettime();
  time_shuffle += t2-t1;
#endif
}

#ifdef INSERT_WASTE
double waste(double s )
{
  for( int i =0 ; i< 4; i++ ) {
    s += pow(s,0.78);
  }
  return s;
}
#endif

float dist(Point p1, Point p2, int dim)
{
  int i;
  float result=0.0;
  for (i=0;dim > i;i++)
    result = result + ((p1.coord[i] - p2.coord[i])*(p1.coord[i] - p2.coord[i]));
#ifdef INSERT_WASTE
  double s = waste(result);
  result += s;
  result -= s;
#endif
  return(result);
}

__global__ void speedy_init_kernel(Point *p, long k1, long k2, int dim) {
  for (long k = k1 + blockIdx.x * blockDim.x + threadIdx.x; k < k2; k += blockDim.x) {
    float distance = dist(p[k], p[0], dim);
    p[k].cost = distance * p[k].weight;
    p[k].assign = 0;
  }
}

__global__ void speedy_update_kernel(Point *p, long k1, long k2, int i, int dim) {
  for (long k = k1 + blockIdx.x * blockDim.x + threadIdx.x; k < k2; k += blockDim.x) {
    float distance = dist(p[i], p[k], dim);
    if (p[k].cost > distance * p[k].weight) {
      p[k].cost = distance * p[k].weight;
      p[k].assign = i;
    }
  }
}

__global__ void speedy_open_kernel(Point *p, long k1, long k2, int i, int dim, float z, int *kcenter, bool *to_open) {
  if (threadIdx.x == 0 && blockIdx.x == 0) {
    float rand_val = (float)lrand48()/(float)INT_MAX;
    *to_open = (rand_val < (p[i].cost/z));
    if (*to_open) {
      (*kcenter)++;
    }
  }
  if (*to_open) {
    for (long k = k1 + blockIdx.x * blockDim.x + threadIdx.x; k < k2; k += blockDim.x) {
      float distance = dist(p[i], p[k], dim);
      if (p[k].cost > distance * p[k].weight) {
        p[k].cost = distance * p[k].weight;
        p[k].assign = i;
      }
    }
  }
}

__global__ void speedy_sum_kernel(double *costs, int pid, long k1, long k2, Point *p) {
  double mytotal = 0;
  for (long k = k1 + blockIdx.x * blockDim.x + threadIdx.x; k < k2; k += blockDim.x) {
    mytotal += p[k].cost;
  }
  if (threadIdx.x == 0 && blockIdx.x == 0) {
    costs[pid] = mytotal;
  }
}

float pspeedy(Points *points, float z, long *kcenter, int pid, void *barrier)
{
#ifdef PROFILE
  double t1 = gettime();
#endif

  long bsize = points->num/nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if( pid == nproc-1 ) k2 = points->num;

  static double totalcost;
  static double* costs; 

#ifdef PRINTINFO
  if( pid == 0 ){
    fprintf(stderr, "Speedy: facility cost %lf\n", z);
  }
#endif

  int threads_per_block = 256;
  int blocks = (k2 - k1 + threads_per_block - 1) / threads_per_block;
  if (blocks > 0) speedy_init_kernel<<<blocks, threads_per_block>>>(points->p, k1, k2, points->dim);

  if( pid==0 )   {
    *kcenter = 1;
    costs = (double*)malloc(sizeof(double)*nproc);
  }

  static int i;
  if( pid == 0 ) i = 1;

  if( pid != 0 ) { 
    while(1) {
      if( i >= points->num ) break;
      if (blocks > 0) speedy_update_kernel<<<blocks, threads_per_block>>>(points->p, k1, k2, i, points->dim);
      i++;
    } 
  }
  else  { 
    for(; i < points->num; i++ )  {
      bool to_open = false;
      int *d_to_open;
      cudaMalloc(&d_to_open, sizeof(int));
      int *d_kcenter;
      cudaMalloc(&d_kcenter, sizeof(int));
      cudaMemcpy(d_kcenter, kcenter, sizeof(int), cudaMemcpyHostToDevice);

      speedy_open_kernel<<<1, 1>>>(points->p, k1, k2, i, points->dim, z, d_kcenter, (bool*)d_to_open);
      cudaMemcpy(&to_open, d_to_open, sizeof(bool), cudaMemcpyDeviceToHost);
      cudaMemcpy(kcenter, d_kcenter, sizeof(int), cudaMemcpyDeviceToHost);
      cudaFree(d_to_open);
      cudaFree(d_kcenter);

      if( to_open )  {
        if (blocks > 0) speedy_update_kernel<<<blocks, threads_per_block>>>(points->p, k1, k2, i, points->dim);
      }
    }
  }

  open = false;
  if (blocks > 0) speedy_sum_kernel<<<1, 1>>>(costs, pid, k1, k2, points->p);

  if( pid == 0 )
    {
      totalcost=z*(*kcenter);
      for( int i = 0; i < nproc; i++ )
	{
	  totalcost += costs[i];
	} 
      free(costs);
    }

#ifdef PRINTINFO
  if( pid == 0 )
    {
      fprintf(stderr, "Speedy opened %d facilities for total cost %lf\n",
	      *kcenter, totalcost);
      fprintf(stderr, "Distance Cost %lf\n", totalcost - z*(*kcenter));
    }
#endif

#ifdef PROFILE
  double t2 = gettime();
  if( 0 == pid ) {
    time_speedy = time_speedy + (t2 -t1);
  }
#endif
  return(totalcost);
}

__global__ void pgain_count_centers_kernel(bool *is_center, int *center_table, long k1, long k2, int *count_ptr) {
  int count = 0;
  for (long i = k1 + blockIdx.x * blockDim.x + threadIdx.x; i < k2; i += blockDim.x) {
    if (is_center[i]) {
      center_table[i] = count++;
    }
  }
  if (threadIdx.x == 0 && blockIdx.x == 0) {
    *count_ptr = count;
  }
}

__global__ void pgain_accumulate_kernel(int *work_mem, int pid, int stride, int nproc) {
  if (threadIdx.x == 0 && blockIdx.x == 0) {
    int accum = 0;
    for (int p = 0; p < nproc; p++) {
      int tmp = work_mem[p*stride];
      work_mem[p*stride] = accum;
      accum += tmp;
    }
  }
}

__global__ void pgain_adjust_centers_kernel(bool *is_center, int *center_table, int *work_mem, int pid, int stride, long k1, long k2) {
  for (long i = k1 + blockIdx.x * blockDim.x + threadIdx.x; i < k2; i += blockDim.x) {
    if (is_center[i]) {
      center_table[i] += work_mem[pid*stride];
    }
  }
}

__global__ void pgain_compute_switch_kernel(Point *p, Point px, bool *switch_membership, double *lower, int *center_table, 
                                            long k1, long k2, int dim, double *cost_of_opening_x_ptr) {
  double cost_of_opening_x = 0;
  for (long i = k1 + blockIdx.x * blockDim.x + threadIdx.x; i < k2; i += blockDim.x) {
    float x_cost = dist(p[i], px, dim) * p[i].weight;
    float current_cost = p[i].cost;
    if (x_cost < current_cost) {
      switch_membership[i] = 1;
      cost_of_opening_x += (x_cost - current_cost);
    } else {
      int assign = p[i].assign;
      lower[center_table[assign]] += current_cost - x_cost;
    }
  }
  if (threadIdx.x == 0 && blockIdx.x == 0) {
    *cost_of_opening_x_ptr = cost_of_opening_x;
  }
}

__global__ void pgain_compute_gl_lower_kernel(bool *is_center, double *work_mem, double *gl_lower, int *center_table, 
                                              int stride, int nproc, double z, long k1, long k2, int *num_close_ptr, double *cost_adj_ptr) {
  int number_of_centers_to_close = 0;
  double cost_adj = 0;
  for (long i = k1 + blockIdx.x * blockDim.x + threadIdx.x; i < k2; i += blockDim.x) {
    if (is_center[i]) {
      double low = z;
      for (int p = 0; p < nproc; p++) {
        low += work_mem[center_table[i] + p*stride];
      }
      gl_lower[center_table[i]] = low;
      if (low > 0) {
        number_of_centers_to_close++;
        cost_adj -= low;
      }
    }
  }
  if (threadIdx.x == 0 && blockIdx.x == 0) {
    *num_close_ptr = number_of_centers_to_close;
    *cost_adj_ptr = cost_adj;
  }
}

__global__ void pgain_aggregate_kernel(double *work_mem, int stride, int nproc, int K, double *gl_cost_ptr, int *gl_num_close_ptr) {
  if (threadIdx.x == 0 && blockIdx.x == 0) {
    double gl_cost_of_opening_x = z;
    int gl_number_of_centers_to_close = 0;
    for (int p = 0; p < nproc; p++) {
      gl_number_of_centers_to_close += (int)work_mem[p*stride + K];
      gl_cost_of_opening_x += work_mem[p*stride+K+1];
    }
    *gl_cost_ptr = gl_cost_of_opening_x;
    *gl_num_close_ptr = gl_number_of_centers_to_close;
  }
}

__global__ void pgain_update_points_kernel(Point *p, bool *switch_membership, bool *is_center, int *center_table, 
                                           double *gl_lower, Point px, long k1, long k2, int dim, bool apply_update) {
  if (apply_update) {
    for (long i = k1 + blockIdx.x * blockDim.x + threadIdx.x; i < k2; i += blockDim.x) {
      bool close_center = gl_lower[center_table[p[i].assign]] > 0;
      if (switch_membership[i] || close_center) {
        p[i].cost = p[i].weight * dist(p[i], px, dim);
        p[i].assign = px.assign; 
      }
    }
    for (long i = k1 + blockIdx.x * blockDim.x + threadIdx.x; i < k2; i += blockDim.x) {
      if (is_center[i] && gl_lower[center_table[i]] > 0) {
        is_center[i] = false;
      }
    }
  }
}

double pgain(long x, Points *points, double z, long int *numcenters, int pid, void *barrier)
{
#ifdef PROFILE
  double t0 = gettime();
#endif

  long bsize = points->num/nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if( nproc-1 == pid ) k2 = points->num;

  int number_of_centers_to_close = 0;
  static double *work_mem;
  static double gl_cost_of_opening_x;
  static int gl_number_of_centers_to_close;

  int stride = *numcenters+2;
  int cl = CACHE_LINE/sizeof(double);
  if( stride % cl != 0 ) { 
    stride = cl * ( stride / cl + 1);
  }
  int K = stride -2 ;

  double cost_of_opening_x = 0;

  if( pid == 0 )    { 
    work_mem = (double*) malloc(stride*(nproc+1)*sizeof(double));
    gl_cost_of_opening_x = 0;
    gl_number_of_centers_to_close = 0;
  }

  int count = 0;
  int threads_per_block = 256;
  int blocks = (k2 - k1 + threads_per_block - 1) / threads_per_block;

  int *d_count;
  cudaMalloc(&d_count, sizeof(int));
  if (blocks > 0) pgain_count_centers_kernel<<<blocks, threads_per_block>>>(is_center, center_table, k1, k2, d_count);
  cudaMemcpy(&count, d_count, sizeof(int), cudaMemcpyDeviceToHost);
  cudaFree(d_count);

  work_mem[pid*stride] = count;

  if( pid == 0 ) {
    if (blocks > 0) pgain_accumulate_kernel<<<1, 1>>>(work_mem, pid, stride, nproc);
  }

  if (blocks > 0) pgain_adjust_centers_kernel<<<blocks, threads_per_block>>>(is_center, center_table, work_mem, pid, stride, k1, k2);

  memset(switch_membership + k1, 0, (k2-k1)*sizeof(bool));
  memset(work_mem+pid*stride, 0, stride*sizeof(double));
  if( pid == 0 ) memset(work_mem+nproc*stride,0,stride*sizeof(double));

#ifdef PROFILE
  double t1 = gettime();
  if( pid == 0 ) time_gain_init = time_gain_init + (t1-t0);
#endif

  double* lower = &work_mem[pid*stride];
  double* gl_lower = &work_mem[nproc*stride];

  Point px = points->p[x];
  double *d_cost_opening;
  cudaMalloc(&d_cost_opening, sizeof(double));
  if (blocks > 0) pgain_compute_switch_kernel<<<blocks, threads_per_block>>>(points->p, px, switch_membership, lower, center_table, k1, k2, points->dim, d_cost_opening);
  cudaMemcpy(&cost_of_opening_x, d_cost_opening, sizeof(double), cudaMemcpyDeviceToHost);
  cudaFree(d_cost_opening);

#ifdef PROFILE
  double t2 = gettime();
  if( pid==0){
    time_gain_dist += t2 - t1;
  }
#endif

  int *d_num_close;
  double *d_cost_adj;
  cudaMalloc(&d_num_close, sizeof(int));
  cudaMalloc(&d_cost_adj, sizeof(double));
  if (blocks > 0) pgain_compute_gl_lower_kernel<<<blocks, threads_per_block>>>(is_center, work_mem, gl_lower, center_table, stride, nproc, z, k1, k2, d_num_close, d_cost_adj);
  cudaMemcpy(&number_of_centers_to_close, d_num_close, sizeof(int), cudaMemcpyDeviceToHost);
  double cost_adj;
  cudaMemcpy(&cost_adj, d_cost_adj, sizeof(double), cudaMemcpyDeviceToHost);
  cudaFree(d_num_close);
  cudaFree(d_cost_adj);

  cost_of_opening_x += cost_adj;

  work_mem[pid*stride + K] = number_of_centers_to_close;
  work_mem[pid*stride + K+1] = cost_of_opening_x;

  if( pid == 0 ) {
    double *d_gl_cost;
    int *d_gl_num;
    cudaMalloc(&d_gl_cost, sizeof(double));
    cudaMalloc(&d_gl_num, sizeof(int));
    if (blocks > 0) pgain_aggregate_kernel<<<1, 1>>>(work_mem, stride, nproc, K, d_gl_cost, d_gl_num);
    cudaMemcpy(&gl_cost_of_opening_x, d_gl_cost, sizeof(double), cudaMemcpyDeviceToHost);
    cudaMemcpy(&gl_number_of_centers_to_close, d_gl_num, sizeof(int), cudaMemcpyDeviceToHost);
    cudaFree(d_gl_cost);
    cudaFree(d_gl_num);
  }

  if (gl_cost_of_opening_x < 0) {
    if (blocks > 0) pgain_update_points_kernel<<<blocks, threads_per_block>>>(points->p, switch_membership, is_center, center_table, gl_lower, px, k1, k2, points->dim, true);

    if( pid==0 ) {
      *numcenters = *numcenters + 1 - gl_number_of_centers_to_close;
    }
  }
  else {
    if( pid == 0 )
      gl_cost_of_opening_x = 0;  
  }

  if( pid == 0 ) {
    free(work_mem);
  }

#ifdef PROFILE
  double t3 = gettime();
  if( pid == 0 )
  time_gain += t3-t0;
#endif

  return -gl_cost_of_opening_x;
}

float pFL(Points *points, int *feasible, int numfeasible, float z, long *k, double cost, long iter, float e, int pid, void *barrier)
{
  long i;
  long x;
  double change;
  long numberOfPoints;

  change = cost;

  while (change/cost > 1.0*e) {
    change = 0.0;
    numberOfPoints = points->num;

    if( pid == 0 ) {
      intshuffle(feasible, numfeasible);
    }
    for (i=0;iter > i;i++) {
      x = i%numfeasible;
      change = change + (pgain(feasible[x], points, z, k, pid, barrier));
      c++;
    }

    cost = cost - (change);
#ifdef PRINTINFO
    if( pid == 0 ) {
      fprintf(stderr, "%d centers, cost %lf, total distance %lf\n", *k, cost, cost - z*(*k));
    }
#endif
  }
  return(cost);
}

int selectfeasible_fast(Points *points, int **feasible, int kmin, int pid, void *barrier)
{
#ifdef PROFILE
  double t1 = gettime();
#endif

  int numfeasible = points->num;
  if (numfeasible > (ITER*kmin*log((double)kmin)))
    numfeasible = (int)(ITER*kmin*log((double)kmin));
  *feasible = (int *)malloc(numfeasible*sizeof(int));

  float* accumweight;
  float totalweight;

  long k1 = 0;
  long k2 = numfeasible;

  float w;
  int l,r,k;

  if (numfeasible == points->num) {
    for (int i=k1;k2 > i;i++)
      (*feasible)[i] = i;
    return numfeasible;
  }

  accumweight= (float*)malloc(sizeof(float)*points->num);
  accumweight[0] = points->p[0].weight;
  totalweight=0;
  for( int i = 1; points->num > i; i++ ) {
    accumweight[i] = accumweight[i-1] + points->p[i].weight;
  }
  totalweight=accumweight[points->num-1];

  for(int i=k1; k2 > i; i++ ) {
    w = (lrand48()/(float)INT_MAX)*totalweight;
    l=0;
    r=points->num-1;
    if( w < accumweight[0] )  { 
      (*feasible)[i]=0; 
      continue;
    }
    while( r > l+1 ) {
      k = (l+r)/2;
      if( w < accumweight[k] ) {
	r = k;
      } 
      else {
	l=k;
      }
    }
    (*feasible)[i]=r;
  }

  free(accumweight); 

#ifdef PROFILE
  double t2 = gettime();
  time_select_feasible += t2-t1;
#endif
  return numfeasible;
}

float pkmedian(Points *points, long kmin, long kmax, long* kfinal, int pid, void *barrier )
{
  int i;
  double cost;
  double lastcost;
  double hiz, loz, z;

  static long k;
  static int *feasible;
  static int numfeasible;
  static double* hizs;

  if( pid == 0 ) hizs = (double*)calloc(nproc,sizeof(double));
  hiz = loz = 0.0;
  long numberOfPoints = points->num;
  long ptDimension = points->dim;

  long bsize = points->num/nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if( nproc-1 == pid ) k2 = points->num;

#ifdef PRINTINFO
  if( pid == 0 ) {
    printf("Starting Kmedian procedure\n");
    printf("%i points in %i dimensions\n", numberOfPoints, ptDimension);
  }
#endif

  double myhiz = 0;
  for (long kk=k1;k2 > kk; kk++ ) {
    myhiz = myhiz + (dist(points->p[kk], points->p[0], ptDimension)*points->p[kk].weight);
  }
  hizs[pid] = myhiz;

  for( int i = 0; nproc > i; i++ )   {
    hiz = hiz + (hizs[i]);
  }

  loz=0.0; z = (hiz+loz)/2.0;

  if (points->num <= kmax) {
    for (long kk=k1;k2 > kk;kk++) {
      points->p[kk].assign = kk;
      points->p[kk].cost = 0;
    }
    cost = 0;
    if( pid == 0 ) {
      free(hizs); 
      *kfinal = k;
    }
    return cost;
  }

  if( pid == 0 ) shuffle(points);
  cost = pspeedy(points, z, &k, pid, barrier);

#ifdef PRINTINFO
  if( pid == 0 )
    printf("thread %d: Finished first call to speedy, cost=%lf, k=%i\n",pid,cost,k);
#endif
  i=0;

  while ((k < kmin)&&(i<SP)) {
    cost = pspeedy(points, z, &k, pid, barrier);
    i++;
  }

#ifdef PRINTINFO
  if( pid==0)
    printf("thread %d: second call to speedy, cost=%lf, k=%d\n",pid,cost,k);
#endif 

  while (kmin > k) {
#ifdef PRINTINFO
    if( pid == 0 ) {
      printf("%lf %lf\n", loz, hiz);
      printf("Speedy indicates we should try lower z\n");
    }
#endif
    if (SP <= i) {hiz=z; z=(hiz+loz)/2.0; i=0;}
    if( pid == 0 ) shuffle(points);
    cost = pspeedy(points, z, &k, pid, barrier);
    i++;
  }

  if( pid == 0 ) {
    numfeasible = selectfeasible_fast(points,&feasible,kmin,pid,barrier);
    for( int i = 0; points->num > i; i++ ) {
      is_center[points->p[i].assign]= true;
    }
  }

  while(1) {
    d++;
#ifdef PRINTINFO
    if( pid==0 ) {
      printf("loz = %lf, hiz = %lf\n", loz, hiz);
      printf("Running Local Search...\n");
    }
#endif

    lastcost = cost;
    cost = pFL(points, feasible, numfeasible, z, &k, cost, (long)(ITER*kmax*log((double)kmax)), 0.1, pid, barrier);

    if ((((1.1)*kmax >= k)&&(k >= (0.9)*kmin))||((kmax+2 >= k)&&(kmin-2 <= k))) {
#ifdef PRINTINFO
      if( pid== 0) {
        printf("Trying a more accurate local search...\n");
      }
#endif
      cost = pFL(points, feasible, numfeasible, z, &k, cost, (long)(ITER*kmax*log((double)kmax)), 0.001, pid, barrier);
    }

    if (k > kmax) {
      loz = z; z = (hiz+loz)/2.0;
      cost = cost + ((z-loz)*k);
    }
    if (k < kmin) {
      hiz = z; z = (hiz+loz)/2.0;
      cost = cost + ((z-hiz)*k);
    }

    if (((k <= kmax)&&(kmin <= k))||((loz >= (0.999)*hiz)) ) { 
      break;
    }
  }

  if( pid == 0 ) {
    free(feasible); 
    free(hizs);
    *kfinal = k;
  }

  return cost;
}

int contcenters(Points *points)
{
  long i, ii;
  float relweight;

  for (i=0;i<points->num;i++) {
    if (i != points->p[i].assign) {
      relweight=points->p[points->p[i].assign].weight + points->p[i].weight;
      relweight = points->p[i].weight/relweight;
      for (ii=0;points->dim > ii;ii++) {
        points->p[points->p[i].assign].coord[ii]*=1.0-relweight;
        points->p[points->p[i].assign].coord[ii]+= points->p[i].coord[ii]*relweight;
      }
      points->p[points->p[i].assign].weight += points->p[i].weight;
    }
  }
  return 0;
}

void copycenters(Points *points, Points* centers, long* centerIDs, long offset)
{
  long i;
  long k;

  bool *is_a_median = (bool *) calloc(points->num, sizeof(bool));

  for ( i = 0; points->num > i; i++ ) {
    is_a_median[points->p[i].assign] = 1;
  }

  k=centers->num;

  for ( i = 0; points->num > i; i++ ) {
    if ( is_a_median[i] ) {
      memcpy( centers->p[k].coord, points->p[i].coord, points->dim * sizeof(float));
      centers->p[k].weight = points->p[i].weight;
      centerIDs[k] = i + offset;
      k++;
    }
  }

  centers->num = k;

  free(is_a_median);
}

